# ================= CONQUISTAS =================

async def check_achievements(channel, user_id, trigger_special=None):
    """Verifica e concede conquistas desbloqueadas ao jogador."""
    player = get_player(user_id)
    if not player:
        return
    earned = player.get("achievements", [])
    new_earned = []

    for ach in ACHIEVEMENTS:
        if ach["id"] in earned:
            continue  # Já tem
        unlocked = False

        if "stat" in ach:
            val = player.get(ach["stat"], 0)
            if val >= ach["threshold"]:
                unlocked = True

        if "special" in ach and trigger_special == ach["special"]:
            unlocked = True

        if unlocked:
            new_earned.append(ach)
            earned.append(ach["id"])

    if new_earned:
        player["achievements"] = earned
        total_xp = sum(a["xp"] for a in new_earned)
        save_player_db(user_id, player)
        add_xp(user_id, total_xp)

        for ach in new_earned:
            is_secret = ach["cat"] == "🔮 Secreta"
            secret_note = "\n🔮 *Uma conquista secreta foi revelada!*" if is_secret else ""
            embed = discord.Embed(
                title="🏆 CONQUISTA DESBLOQUEADA!",
                description=f"*'O narrador anuncia com voz trovejante!'*{secret_note}",
                color=discord.Color.gold()
            )
            embed.add_field(name=f"{ach['cat']} — {ach['name']}", value=f"_{ach['desc']}_\n\n⭐ **+{ach['xp']:,} XP** de recompensa!", inline=False)
            embed.set_footer(text=f"Conquistas desbloqueadas: {len(earned)}/{len(ACHIEVEMENTS)}")
            await channel.send(embed=embed)


# ================= FUNÇÕES BASE =================

def roll_dice():
    return random.randint(1, 10)

def roll_with_bonus(player):
    """Rola dado com bônus de raridade de itens e classe"""
    roll = roll_dice()
    item_bonus = get_item_dice_bonus(player)
    if player.get("class") == "Bardo de Accordis":
        roll = min(10, roll + 1)
    roll = min(10, roll + item_bonus)
    return roll

def get_luck(roll):
    return LUCK_SYSTEM.get(roll, LUCK_SYSTEM[5])

def calc_xp(level):
    return (level ** 2) * 20


def auto_drop_equip(user_id, world, base_chance=0.08):
    """Tenta dropar equipamento/armadura automaticamente. Retorna texto descritivo ou ''."""
    drop_text = ""
    player = get_player(user_id)
    plevel = player.get("level", 1)

    # Define tabela de raridade baseada no nível do jogador
    def _rarity_for_level(level):
        if level >= 500:
            r = random.random()
            if r < 0.10:   return "Primordial"
            elif r < 0.30: return "Divino"
            elif r < 0.55: return "Ancestral"
            elif r < 0.80: return "Mítico"
            elif r < 0.95: return "Lendário"
            else:          return "Épico"
        elif level >= 400:
            r = random.random()
            if r < 0.05:   return "Primordial"
            elif r < 0.18: return "Divino"
            elif r < 0.40: return "Ancestral"
            elif r < 0.65: return "Mítico"
            elif r < 0.85: return "Lendário"
            else:          return "Épico"
        elif level >= 200:
            r = random.random()
            if r < 0.02:   return "Divino"
            elif r < 0.15: return "Ancestral"
            elif r < 0.35: return "Mítico"
            elif r < 0.60: return "Lendário"
            elif r < 0.80: return "Épico"
            else:          return "Raro"
        elif level >= 100:
            r = random.random()
            if r < 0.05:   return "Mítico"
            elif r < 0.20: return "Lendário"
            elif r < 0.45: return "Épico"
            elif r < 0.75: return "Raro"
            else:          return "Incomum"
        else:
            r = random.random()
            if r < 0.03:   return "Lendário"
            elif r < 0.12: return "Épico"
            elif r < 0.35: return "Raro"
            elif r < 0.65: return "Incomum"
            else:          return "Comum"

    # Arma
    if random.random() < base_chance:
        rarity = _rarity_for_level(plevel)
        pool = [w for w in ITEMS["weapons"] if w["rarity"] == rarity]
        if not pool:
            pool = [w for w in ITEMS["weapons"] if w["rarity"] in ["Lendário", "Épico", "Raro"]]
        if pool:
            item = random.choice(pool)
            player["inventory"].append(item["name"])
            drop_text += f"\n🗡️ **{item['name']}** ({rarity}) caiu!"
    # Armadura
    if random.random() < base_chance:
        rarity = _rarity_for_level(plevel)
        pool = [a for a in ITEMS["armor"] if a["rarity"] == rarity]
        if not pool:
            pool = [a for a in ITEMS["armor"] if a["rarity"] in ["Lendário", "Épico", "Raro"]]
        if pool:
            item = random.choice(pool)
            player["inventory"].append(item["name"])
            drop_text += f"\n🛡️ **{item['name']}** ({rarity}) encontrado!"
    if drop_text:
        save_player_db(user_id, player)
    return drop_text

def get_world_cycle(level):
    """Retorna o ciclo de mundo do jogador baseado no nível."""
    if level <= 199:
        return 1, "⚔️ Reinos Mortais", "Nív. 1–199"
    elif level <= 399:
        return 2, "🌌 Reinos Avançados", "Nív. 200–399"
    elif level <= 499:
        return 3, "💫 Dimensões Superiores", "Nív. 400–499"
    else:
        return 4, "♾️ Planos Absolutos", "Nív. 500–600"

def get_world(level, player=None):
    """Retorna o mundo atual do jogador. Respeita current_world se o jogador viajou."""
    if player:
        # Normaliza worlds para lista de ints
        worlds_int = [int(w) for w in player.get("worlds", [1])]
        # ✅ Se o jogador viajou para um mundo específico, SEMPRE usar esse
        cw = player.get("current_world")
        if cw is not None:
            cw = int(cw)
            if cw in WORLDS and cw in worlds_int:
                return WORLDS[cw]
            # current_world inválido: ignorar e usar máximo
        # Sem viagem registrada: usar maior mundo desbloqueado
        available = sorted([k for k in WORLDS.keys() if k in worlds_int], reverse=True)
    else:
        levels = sorted([k for k in WORLDS.keys() if k <= level], reverse=True)
        available = levels
    return WORLDS[available[0]] if available else WORLDS[1]

def create_player(user_id):
    player = {
        "level": 1,
        "xp": 0,
        "hp": 100,
        "max_hp": 100,
        "coins": 0,
        "inventory": [],
        "weapon": None,
        "armor": None,
        "worlds": [1],
        "bosses": [],
        "class": None,
        "pet": None,
        "guild_id": None,
        "active_effects": {},
        "active_quest": None,
        "completed_quests": [],
        "mana": 50,
        "max_mana": 50,
        "pvp_battles": {},
        "alignment_points": 0,
        "pet_farm": [],
        "mana_category": "none",
        "spell_book_unlocked": 0,
        "afk_farming": 0,
        "afk_start": 0,
        "kingdom_data": None,
        "pets_list": [],
        "discovered_map": {},
        "job": None,
        "job_since": 0,
        "city_title": None,
        "knights": [],
        "last_work": 0,
        "last_defend": 0,
        "bio": "",
        "last_force_entry": 0,
        "job_works": {},
        "last_ride": 0,
    }
    save_player_db(user_id, player)
    return player

def get_player(user_id):
    player = get_player_db(user_id)
    if not player:
        player = create_player(user_id)
    return player

def calc_max_mana(player):
    """Calcula mana máxima baseada na classe e nível"""
    cls = player.get("class")
    if not cls or cls not in CLASS_MANA:
        return 50 + player["level"] * 2
    base = CLASS_MANA[cls]["base_mana"]
    per_level = CLASS_MANA[cls]["mana_per_level"]
    return base + (player["level"] - 1) * per_level

def get_item_dice_bonus(player):
    """Retorna bônus no dado baseado na raridade dos equipamentos"""
    bonus = 0
    if player.get("weapon"):
        for w in ITEMS["weapons"]:
            if w["name"] == player["weapon"]:
                bonus += RARITY_DICE_BONUS.get(w["rarity"], 0)
                break
    if player.get("armor"):
        for a in ITEMS["armor"]:
            if a["name"] == player["armor"]:
                bonus += RARITY_DICE_BONUS.get(a["rarity"], 0)
                break
    return bonus

def get_item_sell_price(item_name):
    for weapon in ITEMS["weapons"]:
        if weapon["name"] == item_name:
            rarity_prices = {
                "Comum": 2, "Incomum": 8, "Raro": 20,
                "Épico": 60, "Lendário": 200, "Mítico": 600,
                "Divino": 1500, "Primordial": 4000
            }
            return rarity_prices.get(weapon["rarity"], 5)

    for armor in ITEMS["armor"]:
        if armor["name"] == item_name:
            rarity_prices = {
                "Comum": 2, "Incomum": 8, "Raro": 20,
                "Épico": 60, "Lendário": 200, "Mítico": 600,
                "Divino": 1500, "Primordial": 4000
            }
            return rarity_prices.get(armor["rarity"], 5)

    if item_name in POTIONS:
        rarity_prices = {
            "Comum": 3, "Incomum": 10, "Raro": 30,
            "Épico": 80, "Lendário": 250, "Mítico": 800,
            "Divino": 2000
        }
        return rarity_prices.get(POTIONS[item_name]["rarity"], 5)

    return 3  # recursos

def add_xp(user_id, amount, bypass_boss_gate=False):
    player = get_player(user_id)

    # XP aumentado significativamente
    amount = int(amount * 2.5)

    if player.get("class") == "Bardo de Accordis":
        amount = int(amount * 1.2)

    # Race XP multiplier
    race_name = player.get("race")
    if race_name and race_name in RACES:
        amount = int(amount * RACES[race_name].get("xp_mult", 1.0))

    # Multiplicador de período
    period_data = TIME_PERIODS.get(CURRENT_PERIOD.get("type", "dia"), TIME_PERIODS["dia"])
    amount = int(amount * period_data.get("xp_mult", 1.0))

    # BLOQUEIO DE BOSS: Se o jogador está no nível de boss e não derrotou ele, XP vai para
    # um "balde" de XP pendente que é liberado ao vencer o boss
    boss_gate_levels = {9, 19, 29, 39, 49, 59, 69, 79, 89, 99, 109, 119, 129, 139, 149, 159, 169, 179, 189, 199, 209, 219, 229, 239, 249, 259, 269, 279, 289, 299, 309, 319, 329, 339, 349, 359, 369, 379, 389, 399, 409, 419, 429, 439, 449, 459, 469, 479, 489, 499, 509, 519, 529, 539, 549, 559, 569, 579, 589, 599}
    if not bypass_boss_gate and player["level"] in boss_gate_levels:
        boss_data = get_level_boss(player["level"])
        if boss_data and boss_data["name"] not in player.get("bosses", []):
            # Acumula XP pendente — será liberado ao vencer o boss
            effects = player.get("active_effects", {})
            pending = effects.get("pending_xp", 0) + amount
            effects["pending_xp"] = pending
            player["active_effects"] = effects
            save_player_db(user_id, player)
            return False  # retorna False — nível não mudou

    player["xp"] += amount
    player["total_xp_earned"] = player.get("total_xp_earned", 0) + amount
    leveled = False

    # Bloqueia level-up nos níveis de boss se o boss não foi derrotado
    while player["xp"] >= calc_xp(player["level"]):
        next_level = player["level"] + 1
        # Verifica se o próximo nível é de boss gate — bloqueia progressão além dele
        if player["level"] in boss_gate_levels and not bypass_boss_gate:
            boss_data = get_level_boss(player["level"])
            if boss_data and boss_data["name"] not in player.get("bosses", []):
                # Mantém XP no teto sem ultrapassar
                player["xp"] = calc_xp(player["level"]) - 1
                break
        player["xp"] -= calc_xp(player["level"])
        player["level"] += 1

        class_bonus = 0
        if player.get("class") and player["class"] in CLASSES:
            class_bonus = CLASSES[player["class"]]["hp_bonus"] // 10

        player["max_hp"] += (10 + class_bonus)
        # NÃO restaurar HP ao máximo — apenas aumenta o cap. Use descansar/poções para recuperar!
        player["hp"] = min(player["hp"] + (10 + class_bonus), player["max_hp"])

        # Atualiza mana ao subir de nível
        new_max_mana = calc_max_mana(player)
        player["max_mana"] = new_max_mana
        # Mana também não recupera totalmente — só aumenta o cap
        player["mana"] = min(player.get("mana", 0) + 10, new_max_mana)

        # Verificar desbloqueio livro de feitiços no nível 12
        if player["level"] == 12 and not player.get("spell_book_unlocked"):
            player["spell_book_unlocked"] = 1
            effects = player.get("active_effects", {})
            effects["notify_spellbook"] = True
            player["active_effects"] = effects

        leveled = True
        # Mark that evolution should be checked after level-up
        evol_levels = {40, 80, 120, 160}
        if player["level"] in evol_levels and player.get("class"):
            effects = player.get("active_effects", {})
            effects["check_evolution"] = True
            player["active_effects"] = effects

    save_player_db(user_id, player)

    if player.get("guild_id"):
        distribute_guild_xp(player["guild_id"], amount)

    return leveled


def release_pending_xp(user_id):
    """Libera o XP pendente acumulado durante bloqueio de boss. Chame após derrotar o boss."""
    player = get_player(user_id)
    effects = player.get("active_effects", {})
    pending = effects.pop("pending_xp", 0)
    player["active_effects"] = effects
    save_player_db(user_id, player)
    if pending > 0:
        # Chama add_xp com bypass para liberar tudo de uma vez
        add_xp(user_id, pending // 3, bypass_boss_gate=True)  # divide por 3 pois add_xp multiplica por 2.5
        return pending
    return 0

def distribute_guild_xp(guild_id, amount):
    """Distribui apenas 5% do XP ganho para os demais membros da guilda (nerf)."""
    shared = max(1, int(amount * 0.05))  # 5% do XP original, mínimo 1
    conn = sqlite3.connect(DB_FILE)
    c = conn.cursor()
    c.execute("SELECT members FROM guilds WHERE id = ?", (guild_id,))
    result = c.fetchone()

    if result:
        members = json.loads(result[0])
        for member_id in members:
            member = get_player(member_id)
            if member:
                member["xp"] += shared
                while member["xp"] >= calc_xp(member["level"]):
                    member["xp"] -= calc_xp(member["level"])
                    member["level"] += 1
                    class_bonus = 0
                    if member.get("class") and member["class"] in CLASSES:
                        class_bonus = CLASSES[member["class"]]["hp_bonus"] // 10
                    member["max_hp"] += (10 + class_bonus)
                    member["hp"] = member["max_hp"]
                    for wl in WORLDS.keys():
                        if member["level"] >= wl and wl not in member["worlds"]:
                            member["worlds"].append(wl)
                save_player_db(member_id, member)

    conn.close()

def remove_xp(user_id, amount):
    player = get_player(user_id)
    world = get_world(player["level"], player)

    adjusted_loss = int(amount * world.get("xp_loss_multiplier", 1.0))
    player["xp"] -= adjusted_loss

    while player["xp"] < 0 and player["level"] > 1:
        player["level"] -= 1
        player["xp"] += calc_xp(player["level"])

    if player["xp"] < 0:
        player["xp"] = 0

    if player["level"] == 1 and player["xp"] == 0:
        player["inventory"] = []
        player["weapon"] = None
        player["armor"] = None
        player["worlds"] = [1]
        player["bosses"] = []
        player["hp"] = 100
        player["max_hp"] = 100
        player["coins"] = 0
        player["class"] = None
        player["pet"] = None
        player["active_quest"] = None
        save_player_db(user_id, player)
        return "reset", adjusted_loss

    save_player_db(user_id, player)
    return "ok", adjusted_loss

def add_coins(user_id, amount):
    player = get_player(user_id)
    player["coins"] += amount
    if amount > 0:
        player["total_coins_earned"] = player.get("total_coins_earned", 0) + amount
    save_player_db(user_id, player)

def remove_coins(user_id, amount):
    player = get_player(user_id)
    if player["coins"] >= amount:
        player["coins"] -= amount
        save_player_db(user_id, player)
        return True
    return False

def get_level_boss(level):
    """Retorna boss de level correspondente ao nível do jogador"""
    boss_levels = {
        9: 1, 19: 10, 29: 20, 39: 30, 49: 40, 59: 50,
        69: 60, 79: 70, 89: 80, 99: 90, 109: 100,
        119: 110, 129: 120, 139: 130, 149: 140, 159: 150,
        169: 160, 179: 170, 189: 180, 199: 190,
        # Ciclo 2 — Reinos Avançados (200–399)
        209: 200, 219: 210, 229: 220, 239: 230, 249: 240,
        259: 250, 269: 260, 279: 270, 289: 280, 299: 290,
        309: 300, 319: 310, 329: 320, 339: 330, 349: 340,
        359: 350, 369: 360, 379: 370, 389: 380, 399: 390,
        # Ciclo 3 — Dimensões Superiores (400–499)
        409: 400, 419: 410, 429: 420, 439: 430, 449: 440,
        459: 450, 469: 460, 479: 470, 489: 480, 499: 490,
        # Ciclo 4 — Planos Absolutos (500–600)
        509: 500, 519: 510, 529: 520, 539: 530, 549: 540,
        559: 550, 569: 560, 579: 570, 589: 580, 599: 590,
    }
    world_key = boss_levels.get(level)
    if world_key and world_key in WORLDS:
        return WORLDS[world_key]["boss"]
    # Fallback: usar o mundo mais próximo disponível
    if world_key:
        nearest = max((k for k in WORLDS.keys() if k <= world_key), default=1)
        return WORLDS[nearest]["boss"]
    return None

# ================= VIEWS / BOTÕES =================

# ─────────────────────────────────────────────────────────────
# HELPER: apply race bonuses to player
# ─────────────────────────────────────────────────────────────
def apply_race_bonuses(player, race_name):
    race = RACES[race_name]
    player["max_hp"]  += race["hp_bonus"]
    player["hp"]       = player["max_hp"]
    player["race"]     = race_name
    return player


# ─────────────────────────────────────────────────────────────
# HELPER: get current skills for player (tiered system)
# ─────────────────────────────────────────────────────────────
def get_player_skills(player):
    cls = player.get("class", "Guardião de Ashenvorn") or "Guardião de Ashenvorn"
    lvl = player.get("level", 1)
    tier_data = CLASS_TIERED_SKILLS.get(cls)
    if not tier_data:
        # fallback to old CLASS_SKILLS
        return CLASS_SKILLS.get(cls, CLASS_SKILLS["Guardião de Ashenvorn"])

    skills = list(tier_data["basic"])
    if lvl >= 40:
        skills += tier_data.get("intermediate", [])
    if lvl >= 80:
        skills += tier_data.get("advanced", [])
    # Supreme skill
    supreme = tier_data.get("supreme")
    if supreme and supreme["name"] in player.get("supreme_skills", []):
        skills.append(supreme)
    # Specialization special skill
    spec = player.get("specialization")
    if spec and spec in CLASS_SPECIALIZATIONS:
        spec_skill = CLASS_SPECIALIZATIONS[spec].get("special_skill")
        if spec_skill:
            skills.append(spec_skill)
    return skills


# ─────────────────────────────────────────────────────────────
# HELPER: check and trigger class evolution prompt
# ─────────────────────────────────────────────────────────────
async def check_class_evolution(channel, user_id):
    player = get_player(user_id)
    if not player or not player.get("class"):
        return
    cls = player["class"]
    lvl = player["level"]
    tree = CLASS_EVOLUTION_TREE.get(cls)
    if not tree:
        return
    current_tier = player.get("class_tier", 0)
    evolution_levels = sorted(tree.keys())
    # Which tiers haven't been taken yet
    for evo_lvl in evolution_levels:
        tier_index = evolution_levels.index(evo_lvl) + 1
        if lvl >= evo_lvl and current_tier < tier_index:
            evo_data = tree[evo_lvl]
            specs = evo_data["spec_options"]
            embed = discord.Embed(
                title=f"🌟 Evolução de Classe Disponível!",
                description=(
                    f"**{cls}** pode evoluir para **{evo_data['name']}**!\n\n"
                    f"Escolha sua especialização abaixo.\n"
                    f"*A escolha altera suas habilidades, passivas e estilo de combate.*"
                ),
                color=discord.Color.gold()
            )
            # Calcular tier que será aplicado nesta evolução
            preview_tier = tier_index
            PREVIEW_MULTIPLIERS = {
                1: {"hp": 1.0,  "atk": 1.0,  "def": 1.0,  "extra_hp":    0, "extra_atk":   0, "extra_def":   0},
                2: {"hp": 2.5,  "atk": 2.5,  "def": 2.5,  "extra_hp":   50, "extra_atk":  20, "extra_def":  15},
                3: {"hp": 5.0,  "atk": 5.0,  "def": 5.0,  "extra_hp":  150, "extra_atk":  60, "extra_def":  45},
                4: {"hp": 10.0, "atk": 10.0, "def": 10.0, "extra_hp":  400, "extra_atk": 150, "extra_def": 120},
                5: {"hp": 20.0, "atk": 20.0, "def": 20.0, "extra_hp": 1000, "extra_atk": 400, "extra_def": 300},
                6: {"hp": 40.0, "atk": 40.0, "def": 40.0, "extra_hp": 2500, "extra_atk":1000, "extra_def": 750},
                7: {"hp": 80.0, "atk": 80.0, "def": 80.0, "extra_hp": 6000, "extra_atk":2500, "extra_def":1800},
            }
            PREVIEW_MIN_HP  = {1: 10, 2: 80,  3: 200, 4: 500,  5: 1200,  6: 3000,  7: 7000}
            PREVIEW_MIN_ATK = {1:  5, 2: 30,  3:  80, 4: 200,  5:  500,  6: 1200,  7: 3000}
            PREVIEW_MIN_DEF = {1:  0, 2: 20,  3:  55, 4: 130,  5:  350,  6:  850,  7: 2000}
            # ── TIER 4+ (após lv 130): bônus diferenciados por identidade de classe ──
            CLASS_STAT_IDENTITY = {
                # ── CLASSES ORIGINAIS ──────────────────────────────────────────────
                # Ofensivas: mais ATK, menos DEF/HP
                "Mago Arcano de Altheron":                    {"hp": 0.70, "atk": 1.50, "def": 0.60},
                "Assassino das Sombras":               {"hp": 0.75, "atk": 1.45, "def": 0.65},
                "Arqueiro de Sylvenmara":                {"hp": 0.80, "atk": 1.35, "def": 0.70},
                "Necromante do Veil":              {"hp": 0.75, "atk": 1.40, "def": 0.65},
                "Berserker Orkrioniano":               {"hp": 1.20, "atk": 1.40, "def": 0.50},  # HP alto + ATK, DEF baixa
                # Defensivas: mais HP/DEF, menos ATK
                "Guardião de Ashenvorn":               {"hp": 1.20, "atk": 1.10, "def": 1.20},
                "Paladino da Luz":                {"hp": 1.15, "atk": 1.05, "def": 1.30},
                # Balanceadas/suporte
                "Druida de Sylvenmara":                  {"hp": 1.10, "atk": 1.10, "def": 1.10},
                "Monge de Fiorveth":                   {"hp": 1.05, "atk": 1.20, "def": 1.05},
                "Bardo de Accordis":                   {"hp": 1.00, "atk": 1.00, "def": 1.10},  # suporte puro

                # ── CLASSES EXTRAS ──────────────────────────────────────────────
                # Tank sombrio: bom HP e ATK, DEF média
                "Cavaleiro das Sombras":   {"hp": 1.20, "atk": 1.25, "def": 0.90},
                # Invocador: fraco fisicamente, força vem dos bichos
                "Invocador":               {"hp": 0.80, "atk": 1.30, "def": 0.75},
                # Runesmith: híbrido DEF/ATK, artesão de batalha
                "Runesmith":               {"hp": 1.00, "atk": 1.15, "def": 1.25},
                # Caçador: ofensivo de precisão, similar ao Arqueiro
                "Cazador de Recompensas":  {"hp": 0.80, "atk": 1.40, "def": 0.70},
                # Xamã: suporte espiritual, HP e cura, ATK baixo
                "Xamã":                    {"hp": 1.20, "atk": 0.90, "def": 1.10},
                # Tempesteiro: mago ofensivo elétrico, explode mas é frágil
                "Tempesteiro":             {"hp": 0.70, "atk": 1.55, "def": 0.60},
                # Ilusionista: esquiva, controle, dano médio
                "Ilusionista":             {"hp": 0.75, "atk": 1.30, "def": 0.75},
                # Alquimista: suporte/explosivo, balanceado com leve ATK
                "Alquimista":              {"hp": 1.00, "atk": 1.20, "def": 1.00},
                # Guardião do Abismo: tank escuro, muito DEF e HP
                "Guardião do Abismo":      {"hp": 1.30, "atk": 0.95, "def": 1.35},
                # Dançarino da Morte: assassino ágil, burst de ATK
                "Dançarino da Morte":      {"hp": 0.75, "atk": 1.50, "def": 0.60},
                # Oráculo: mago de controle, ATK mágico alto, frágil
                "Oráculo":                 {"hp": 0.70, "atk": 1.45, "def": 0.65},
                # Colossus: tank puro, máximo HP e DEF do jogo
                "Colossus":                {"hp": 1.50, "atk": 0.80, "def": 1.50},
                # Devorador de Almas: dreno de vida, HP + ATK
                "Devorador de Almas":      {"hp": 1.10, "atk": 1.35, "def": 0.80},
                # Arauto Celestial: protetor sagrado, DEF e HP, pouco ATK
                "Arauto Celestial":        {"hp": 1.20, "atk": 0.90, "def": 1.30},
                # Lançador de Venenos: dano por veneno, ATK alto, baixa sobrevivência
                "Lançador de Venenos":     {"hp": 0.75, "atk": 1.45, "def": 0.65},
            }
            identity = CLASS_STAT_IDENTITY.get(cls, {"hp": 1.0, "atk": 1.0, "def": 1.0})
            pmult = dict(PREVIEW_MULTIPLIERS.get(preview_tier, PREVIEW_MULTIPLIERS[7]))
            # Aplicar identidade apenas nos tiers 4+ (level 130+)
            if preview_tier >= 4:
                pmult["hp"]  = pmult["hp"]  * identity["hp"]
                pmult["atk"] = pmult["atk"] * identity["atk"]
                pmult["def"] = pmult["def"] * identity["def"]
                pmult["extra_hp"]  = int(pmult["extra_hp"]  * identity["hp"])
                pmult["extra_atk"] = int(pmult["extra_atk"] * identity["atk"])
                pmult["extra_def"] = int(pmult["extra_def"] * identity["def"])
            for s in specs:
                spec_data = CLASS_SPECIALIZATIONS.get(s)
                if spec_data:
                    b_hp  = int(spec_data.get("bonus_hp", 0)  * pmult["hp"])  + pmult["extra_hp"]
                    b_atk = int(spec_data.get("bonus_atk", 0) * pmult["atk"]) + pmult["extra_atk"]
                    b_def = int(spec_data.get("bonus_def", 0) * pmult["def"]) + pmult["extra_def"]
                    b_hp  = max(b_hp,  PREVIEW_MIN_HP.get(preview_tier, 7000))
                    b_atk = max(b_atk, PREVIEW_MIN_ATK.get(preview_tier, 3000))
                    b_def = max(b_def, PREVIEW_MIN_DEF.get(preview_tier, 2000))
                    identity_note = ""
                    if preview_tier >= 4:
                        atk_id = identity["atk"]
                        if atk_id >= 1.35:
                            identity_note = "\n⚔️ *Classe ofensiva — ATK amplificado!*"
                        elif identity["def"] >= 1.20:
                            identity_note = "\n🛡️ *Classe defensiva — HP e DEF amplificados!*"
                        else:
                            identity_note = "\n⚖️ *Classe balanceada — atributos equilibrados.*"
                    embed.add_field(
                        name=f"{spec_data['emoji']} {s}",
                        value=(
                            f"{spec_data['desc']}\n"
                            f"**Passiva:** {spec_data['passive']}\n"
                            f"📊 **Bônus:** ❤️ +{b_hp} HP | ⚔️ +{b_atk} ATK | 🛡️ +{b_def} DEF{identity_note}"
                        ),
                        inline=False
                    )
            view = ClassEvolutionView(user_id, cls, evo_data["name"], specs, tier_index)
            await channel.send(embed=embed, view=view)
            return  # show one at a time


# ─────────────────────────────────────────────────────────────
# VIEW: Race selection (page 1 of 4)
# ─────────────────────────────────────────────────────────────
class RaceSelectView(discord.ui.View):
    def __init__(self, user_id, page=0, timeout=180, allow_change=False):
        super().__init__(timeout=timeout)
        self.user_id = user_id
        self.page = page
        self.answered = False
        self.allow_change = allow_change
        all_races = list(RACES.keys())
        # 5 per page
        chunk = all_races[page*5:(page+1)*5]
        colors = [
            discord.ButtonStyle.primary, discord.ButtonStyle.success,
            discord.ButtonStyle.danger, discord.ButtonStyle.secondary,
            discord.ButtonStyle.primary
        ]
        for i, race_name in enumerate(chunk):
            race_data = RACES[race_name]
            btn = discord.ui.Button(
                label=race_name,
                style=colors[i % len(colors)],
                emoji=race_data["emoji"],
                row=0
            )
            btn.callback = self.make_cb(race_name)
            self.add_item(btn)
        # Nav buttons
        total_pages = (len(all_races) + 4) // 5
        if page > 0:
            prev_btn = discord.ui.Button(label="◀ Anterior", style=discord.ButtonStyle.secondary, row=1)
            prev_btn.callback = self.make_nav(page - 1)
            self.add_item(prev_btn)
        if page < total_pages - 1:
            next_btn = discord.ui.Button(label="Próxima ▶", style=discord.ButtonStyle.secondary, row=1)
            next_btn.callback = self.make_nav(page + 1)
            self.add_item(next_btn)

    def make_cb(self, race_name):
        async def callback(interaction: discord.Interaction):
            if str(interaction.user.id) != str(self.user_id):
                return await interaction.response.send_message("❌ Esta escolha não é sua!", ephemeral=True)
            if self.answered:
                return
            self.answered = True
            player = get_player(self.user_id)
            old_race = player.get("race")

            if old_race and not self.allow_change:
                return await interaction.response.send_message(f"❌ Você já é um(a) **{old_race}**!", ephemeral=True)
            if old_race and self.allow_change and old_race == race_name:
                return await interaction.response.send_message(f"❌ Você já é **{old_race}**! Escolha uma raça diferente.", ephemeral=True)

            race_data = RACES[race_name]

            if self.allow_change and old_race:
                # TROCA DE RAÇA: remove bônus antigos, aplica novos, reseta stage
                old_race_data = RACES.get(old_race, {})
                player["max_hp"] = max(10, player["max_hp"] - old_race_data.get("hp_bonus", 0))
                player["hp"] = min(player["hp"], player["max_hp"])
                # Reseta evoluções de raça (do stage anterior)
                old_stage = player.get("race_stage", 0)
                if old_stage > 0:
                    old_evos = RACE_EVOLUTION_TREE.get(old_race, [])
                    for i in range(old_stage):
                        if i < len(old_evos):
                            evo = old_evos[i]
                            player["max_hp"] = max(10, player["max_hp"] - evo["hp_bonus"])
                player["race_stage"] = 0
                player["race"] = race_name
                player["max_hp"] += race_data["hp_bonus"]
                player["hp"] = min(player["hp"] + race_data["hp_bonus"], player["max_hp"])
                action_title = f"🔄 Raça Trocada: {old_race} → {race_name}!"
                footer_text = "⚠️ Evoluções de raça foram resetadas. Use 'evoluir raça' para evoluir novamente!"
                color = discord.Color.orange()
            else:
                apply_race_bonuses(player, race_name)
                action_title = f"{race_data['emoji']} Raça Escolhida: {race_name}!"
                footer_text = "Agora use 'escolher classe' para completar seu personagem!"
                color = discord.Color.purple()

            save_player_db(self.user_id, player)
            embed = discord.Embed(
                title=action_title,
                description=f"*{race_data['lore']}*\n\n{race_data['description']}",
                color=color
            )
            embed.add_field(name="❤️ Bônus HP",  value=f"+{race_data['hp_bonus']}",  inline=True)
            embed.add_field(name="⚔️ Bônus ATK", value=f"+{race_data['atk_bonus']}", inline=True)
            embed.add_field(name="🛡️ Bônus DEF", value=f"+{race_data['def_bonus']}", inline=True)
            embed.add_field(name="✨ Passiva",    value=race_data["passive"],          inline=False)
            embed.set_footer(text=footer_text)
            await interaction.response.edit_message(embed=embed, view=None)
        return callback

    def make_nav(self, new_page):
        async def callback(interaction: discord.Interaction):
            if str(interaction.user.id) != str(self.user_id):
                return await interaction.response.send_message("❌ Esta não é sua seleção!", ephemeral=True)
            all_races = list(RACES.keys())
            chunk = all_races[new_page*5:(new_page+1)*5]
            embed = discord.Embed(
                title=f"🧬 Escolha sua Raça (Página {new_page+1})",
                description="Sua raça define bônus permanentes e passivas únicas.",
                color=discord.Color.purple()
            )
            for rn in chunk:
                rd = RACES[rn]
                embed.add_field(
                    name=f"{rd['emoji']} {rn}",
                    value=f"{rd['description']}\n**Passiva:** {rd['passive']}\n**HP:** +{rd['hp_bonus']} | **ATK:** +{rd['atk_bonus']} | **DEF:** +{rd['def_bonus']}",
                    inline=False
                )
            new_view = RaceSelectView(self.user_id, page=new_page, allow_change=self.allow_change)
            await interaction.response.edit_message(embed=embed, view=new_view)
        return callback


# ─────────────────────────────────────────────────────────────
# VIEW: Class selection (paginated, 5 per page across 6 pages)
# ─────────────────────────────────────────────────────────────
class ClassSelectView(discord.ui.View):
    def __init__(self, user_id, page=0, timeout=180, allow_change=False):
        super().__init__(timeout=timeout)
        self.user_id = user_id
        self.page = page
        self.answered = False
        self.allow_change = allow_change
        all_classes = list(CLASSES.keys())
        chunk = all_classes[page*5:(page+1)*5]
        colors = [
            discord.ButtonStyle.primary, discord.ButtonStyle.success,
            discord.ButtonStyle.danger, discord.ButtonStyle.secondary,
            discord.ButtonStyle.primary
        ]
        for i, class_name in enumerate(chunk):
            class_data = CLASSES[class_name]
            btn = discord.ui.Button(
                label=class_name[:25],
                style=colors[i % len(colors)],
                emoji=class_data["emoji"],
                row=0
            )
            btn.callback = self.make_cb(class_name)
            self.add_item(btn)
        total_pages = (len(all_classes) + 4) // 5
        if page > 0:
            prev_btn = discord.ui.Button(label="◀ Anterior", style=discord.ButtonStyle.secondary, row=1)
            prev_btn.callback = self.make_nav(page - 1)
            self.add_item(prev_btn)
        if page < total_pages - 1:
            next_btn = discord.ui.Button(label="Próxima ▶", style=discord.ButtonStyle.secondary, row=1)
            next_btn.callback = self.make_nav(page + 1)
            self.add_item(next_btn)

    def make_cb(self, class_name):
        async def callback(interaction: discord.Interaction):
            if str(interaction.user.id) != str(self.user_id):
                return await interaction.response.send_message("❌ Esta escolha não é sua!", ephemeral=True)
            if self.answered:
                return
            self.answered = True
            player = get_player(self.user_id)
            old_class = player.get("class")
            if old_class and not self.allow_change:
                return await interaction.response.send_message(f"❌ Você já é um(a) **{old_class}**!", ephemeral=True)
            if old_class and self.allow_change and old_class == class_name:
                return await interaction.response.send_message(f"❌ Você já é **{old_class}**! Escolha uma classe diferente.", ephemeral=True)

            class_data = CLASSES[class_name]

            if self.allow_change and old_class:
                # TROCA DE CLASSE: remove bônus antigos, aplica novos, reseta tiers/spec
                old_class_data = CLASSES.get(old_class, {})
                # Remove bônus da classe antiga (somente o bônus base da classe)
                player["max_hp"] = max(10, player["max_hp"] - old_class_data.get("hp_bonus", 0))
                player["hp"] = min(player["hp"], player["max_hp"])
                # Reseta evolução de classe (tiers/spec resetam pois a classe mudou)
                player["class_tier"] = 0
                player["specialization"] = None
                player["supreme_skills"] = []
                # Aplica nova classe
                player["class"] = class_name
                player["max_hp"] += class_data["hp_bonus"]
                player["hp"] = min(player["hp"] + class_data["hp_bonus"], player["max_hp"])
                action_title = f"🔄 Classe Trocada: {old_class} → {class_name}!"
                footer_text = "⚠️ Evoluções e especializações foram resetadas. Reevolua sua classe!"
                color = discord.Color.orange()
            else:
                # ESCOLHA INICIAL
                player["class"] = class_name
                player["max_hp"] += class_data["hp_bonus"]
                player["hp"] = player["max_hp"]
                action_title = f"{class_data['emoji']} Classe Escolhida: {class_name}!"
                footer_text = "Use 'habilidades' para ver suas skills. Evolua nos níveis 40, 80, 120, 160, 200, 400 e 500!"
                color = discord.Color.gold()

            # Apply race affinity bonus if player has a race
            race = player.get("race")
            affinity_bonus = ""
            if race and race in class_data.get("race_affinity", []):
                player["max_hp"] += 15
                player["hp"] = player["max_hp"]
                affinity_bonus = f"\n\n🌟 **Bônus de Afinidade!** Sua raça **{race}** tem afinidade com esta classe!\n+15 HP bônus adicional."
            save_player_db(self.user_id, player)
            embed = discord.Embed(
                title=action_title,
                description=f"{class_data['description']}{affinity_bonus}",
                color=color
            )
            embed.add_field(name="💪 Bônus ATK", value=f"+{class_data['atk_bonus']}", inline=True)
            embed.add_field(name="🛡️ Bônus DEF", value=f"+{class_data['def_bonus']}", inline=True)
            embed.add_field(name="❤️ Bônus HP",  value=f"+{class_data['hp_bonus']}", inline=True)
            tree = CLASS_EVOLUTION_TREE.get(class_name)
            if tree:
                evo_levels = sorted(tree.keys())
                evo_text = " → ".join([f"Nv.{lvl} ({tree[lvl]['name']})" for lvl in evo_levels])
                embed.add_field(name="🌟 Árvore de Evolução", value=evo_text, inline=False)
            embed.set_footer(text=footer_text)
            await interaction.response.edit_message(embed=embed, view=None)
        return callback

    def make_nav(self, new_page):
        async def callback(interaction: discord.Interaction):
            if str(interaction.user.id) != str(self.user_id):
                return await interaction.response.send_message("❌ Esta não é sua seleção!", ephemeral=True)
            all_classes = list(CLASSES.keys())
            chunk = all_classes[new_page*5:(new_page+1)*5]
            total_pages = (len(all_classes) + 4) // 5
            embed = discord.Embed(
                title=f"🎭 Escolha sua Classe (Página {new_page+1}/{total_pages})",
                description="Cada classe tem árvore de evolução e especializações únicas.",
                color=discord.Color.blue()
            )
            for cn in chunk:
                cd = CLASSES[cn]
                tree = CLASS_EVOLUTION_TREE.get(cn)
                evo_hint = ""
                if tree:
                    evo_hint = f"\n🌟 Evolui nos níveis: {', '.join(str(k) for k in sorted(tree.keys()))}"
                embed.add_field(
                    name=f"{cd['emoji']} {cn}",
                    value=f"{cd['description']}\n**ATK:** +{cd['atk_bonus']} | **DEF:** +{cd['def_bonus']} | **HP:** +{cd['hp_bonus']}{evo_hint}",
                    inline=False
                )
            new_view = ClassSelectView(self.user_id, page=new_page, allow_change=self.allow_change)
            await interaction.response.edit_message(embed=embed, view=new_view)
        return callback


