# ─────────────────────────────────────────────────────────────
# VIEW: Class Evolution / Specialization choice
# ─────────────────────────────────────────────────────────────
class ClassEvolutionView(discord.ui.View):
    def __init__(self, user_id, base_class, evolved_name, spec_options, new_tier, timeout=180):
        super().__init__(timeout=timeout)
        self.user_id = user_id
        self.base_class = base_class
        self.evolved_name = evolved_name
        self.answered = False
        colors = [discord.ButtonStyle.success, discord.ButtonStyle.danger]
        for i, spec in enumerate(spec_options):
            spec_data = CLASS_SPECIALIZATIONS.get(spec, {})
            btn = discord.ui.Button(
                label=spec[:25],
                style=colors[i % len(colors)],
                emoji=spec_data.get("emoji", "⭐"),
                row=0
            )
            btn.callback = self.make_cb(spec, new_tier)
            self.add_item(btn)

    def make_cb(self, spec_name, new_tier):
        async def callback(interaction: discord.Interaction):
            if str(interaction.user.id) != str(self.user_id):
                return await interaction.response.send_message("❌ Esta evolução não é sua!", ephemeral=True)
            if self.answered:
                return
            self.answered = True
            player = get_player(self.user_id)
            spec_data = CLASS_SPECIALIZATIONS.get(spec_name, {})
            player["class"] = self.base_class
            player["specialization"] = spec_name
            player["class_tier"] = new_tier

            # ── Status escalonados por tier ─────────────────────────────
            # Tier 1 (nível 40):  1× base
            # Tier 2 (nível 80):  2.5× base + bônus extra
            # Tier 3 (nível 120): 5× base + bônus extra grande
            # Tier 4 (nível 160): 10× base + bônus máximo (poder divino)
            BASE_HP  = spec_data.get("bonus_hp",  0)
            BASE_ATK = spec_data.get("bonus_atk", 0)
            BASE_DEF = spec_data.get("bonus_def", 0)

            TIER_MULTIPLIERS = {
                1: {"hp": 1.0,   "atk": 1.0,   "def": 1.0,   "extra_hp":    0, "extra_atk":   0, "extra_def":   0},
                2: {"hp": 2.5,   "atk": 2.5,   "def": 2.5,   "extra_hp":   50, "extra_atk":  20, "extra_def":  15},
                3: {"hp": 5.0,   "atk": 5.0,   "def": 5.0,   "extra_hp":  150, "extra_atk":  60, "extra_def":  45},
                4: {"hp": 10.0,  "atk": 10.0,  "def": 10.0,  "extra_hp":  400, "extra_atk": 150, "extra_def": 120},
                5: {"hp": 20.0,  "atk": 20.0,  "def": 20.0,  "extra_hp": 1000, "extra_atk": 400, "extra_def": 300},
                6: {"hp": 40.0,  "atk": 40.0,  "def": 40.0,  "extra_hp": 2500, "extra_atk":1000, "extra_def": 750},
                7: {"hp": 80.0,  "atk": 80.0,  "def": 80.0,  "extra_hp": 6000, "extra_atk":2500, "extra_def":1800},
            }
            mult = TIER_MULTIPLIERS.get(new_tier, TIER_MULTIPLIERS[7])

            bonus_hp  = int(BASE_HP  * mult["hp"])  + mult["extra_hp"]
            bonus_atk = int(BASE_ATK * mult["atk"]) + mult["extra_atk"]
            bonus_def = int(BASE_DEF * mult["def"]) + mult["extra_def"]

            # Garantir mínimos por tier (mesmo specs sem bônus base ganham algo)
            MIN_HP  = {1: 10, 2: 80,  3: 200, 4: 500,  5: 1200,  6: 3000,  7: 7000}
            MIN_ATK = {1:  5, 2: 30,  3:  80, 4: 200,  5:  500,  6: 1200,  7: 3000}
            MIN_DEF = {1:  0, 2: 20,  3:  55, 4: 130,  5:  350,  6:  850,  7: 2000}
            bonus_hp  = max(bonus_hp,  MIN_HP.get(new_tier, 7000))
            bonus_atk = max(bonus_atk, MIN_ATK.get(new_tier, 3000))
            bonus_def = max(bonus_def, MIN_DEF.get(new_tier, 2000))

            # Aplicar bônus ao jogador
            player["max_hp"] += bonus_hp
            player["hp"] = min(player["hp"] + bonus_hp, player["max_hp"])
            save_player_db(self.user_id, player)

            # Nomes dos tiers para exibição
            TIER_NAMES = {
                1: "Tier I — Elite",        2: "Tier II — Mestre",
                3: "Tier III — Lendário",   4: "Tier IV — Divino",
                5: "Tier V — Transcendente",6: "Tier VI — Dimensional",
                7: "Tier VII — ABSOLUTO",
            }
            TIER_COLORS = {
                1: discord.Color.blue(),                2: discord.Color.gold(),
                3: discord.Color.from_rgb(255, 60, 0),  4: discord.Color.from_rgb(200, 0, 255),
                5: discord.Color.from_rgb(0, 220, 255), 6: discord.Color.from_rgb(255, 0, 128),
                7: discord.Color.from_rgb(255, 215, 0),
            }
            TIER_EMOJIS = {
                1: "🔵", 2: "🌟", 3: "🔥", 4: "👑",
                5: "💎", 6: "🌀", 7: "⚡",
            }

            embed = discord.Embed(
                title=f"{TIER_EMOJIS.get(new_tier,'⚡')} EVOLUÇÃO {TIER_NAMES.get(new_tier,'ABSOLUTO').upper()}!",
                description=(
                    f"Você evoluiu para **{self.evolved_name}**!\n"
                    f"Especialização: **{spec_name}** {spec_data.get('emoji','')}\n\n"
                    f"*{spec_data.get('desc', '')}*\n\n"
                    f"**Passiva:** {spec_data.get('passive', '')}"
                ),
                color=TIER_COLORS.get(new_tier, discord.Color.from_rgb(255, 215, 0))
            )
            if spec_data.get("special_skill"):
                sk = spec_data["special_skill"]
                embed.add_field(name="⚡ Habilidade Especial", value=f"{sk['name']} — {sk['desc']}", inline=False)
            embed.add_field(name="❤️ HP Ganho",  value=f"**+{bonus_hp}**",  inline=True)
            embed.add_field(name="⚔️ ATK Ganho", value=f"**+{bonus_atk}**", inline=True)
            embed.add_field(name="🛡️ DEF Ganho", value=f"**+{bonus_def}**", inline=True)
            if new_tier >= 2:
                embed.add_field(
                    name=f"📈 Escalamento de Poder",
                    value=(
                        f"*Cada tier multiplica os bônus da especialização.*\n"
                        f"I:×1 | II:×2.5 | III:×5 | IV:×10 | V:×20 | VI:×40 | VII:×80"
                    ),
                    inline=False
                )
            embed.set_footer(text=f"Tier {new_tier}/7 — Use 'habilidades' para ver suas skills!")
            await interaction.response.edit_message(embed=embed, view=None)
        return callback


# ─────────────────────────────────────────────────────────────
# VIEW: Class Change Confirmation (pays coins, then shows class select)
# ─────────────────────────────────────────────────────────────
class ClassChangeConfirmView(discord.ui.View):
    def __init__(self, user_id, cost, timeout=60):
        super().__init__(timeout=timeout)
        self.user_id = user_id
        self.cost = cost

    @discord.ui.button(label="✅ Confirmar Troca", style=discord.ButtonStyle.danger, emoji="🔄")
    async def confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
        if str(interaction.user.id) != str(self.user_id):
            return await interaction.response.send_message("❌ Esta confirmação não é sua!", ephemeral=True)
        player = get_player(self.user_id)
        if player.get("coins", 0) < self.cost:
            return await interaction.response.send_message(f"❌ Você não tem coins suficientes! Necessário: {self.cost} 💰", ephemeral=True)
        # Deduct coins
        player["coins"] -= self.cost
        save_player_db(self.user_id, player)
        # Show class select with allow_change=True
        all_classes = list(CLASSES.keys())
        total_pages = (len(all_classes) + 4) // 5
        embed = discord.Embed(
            title="🔄 Escolha sua Nova Classe",
            description=(
                f"✅ **{self.cost} coins debitados.** Escolha sua nova classe:\n"
                f"*Sua classe anterior e todas as evoluções serão substituídas.*"
            ),
            color=discord.Color.blue()
        )
        chunk = all_classes[:5]
        for cn in chunk:
            cd = CLASSES[cn]
            tree = CLASS_EVOLUTION_TREE.get(cn)
            evo_hint = (f"\n🌟 Evolui: {', '.join(str(k) for k in sorted(tree.keys()))}") if tree else ""
            embed.add_field(
                name=f"{cd['emoji']} {cn}",
                value=f"{cd['description']}\n**ATK:** +{cd['atk_bonus']} | **DEF:** +{cd['def_bonus']} | **HP:** +{cd['hp_bonus']}{evo_hint}",
                inline=False
            )
        view = ClassSelectView(self.user_id, page=0, allow_change=True)
        await interaction.response.edit_message(embed=embed, view=view)

    @discord.ui.button(label="❌ Cancelar", style=discord.ButtonStyle.secondary)
    async def cancel(self, interaction: discord.Interaction, button: discord.ui.Button):
        if str(interaction.user.id) != str(self.user_id):
            return await interaction.response.send_message("❌ Esta confirmação não é sua!", ephemeral=True)
        await interaction.response.edit_message(
            content="❌ Troca de classe cancelada.",
            embed=None, view=None
        )


