class DungeonBossStartView(discord.ui.View):
    """Botões exibidos ANTES de enfrentar o boss de dungeon — escolha: sozinho, aliado ou guilda"""
    def __init__(self, user_id, boss_data, dungeon, channel=None, timeout=60):
        super().__init__(timeout=timeout)
        self.user_id = user_id
        self.boss_data = boss_data
        self.dungeon = dungeon
        self._channel = channel
        self.answered = False
        self._message = None  # guardado após send

    @staticmethod
    def apply_ally_buff(boss_data: dict, num_allies: int) -> dict:
        """Aplica +20% HP e +10% ATK por aliado adicional (além do jogador principal)."""
        if num_allies <= 0:
            return boss_data
        buffed = dict(boss_data)
        hp_mult  = 1.0 + num_allies * 0.20   # +20% HP por aliado
        atk_mult = 1.0 + num_allies * 0.10   # +10% ATK por aliado
        buffed["hp"]  = int(buffed["hp"]  * hp_mult)
        buffed["atk"] = int(buffed["atk"] * atk_mult)
        # XP e coins também sobem levemente para compensar
        buffed["xp"]  = int(buffed.get("xp", 0)  * (1.0 + num_allies * 0.15))
        old_coins = buffed.get("coins", (5, 10))
        buffed["coins"] = (
            int(old_coins[0] * (1.0 + num_allies * 0.10)),
            int(old_coins[1] * (1.0 + num_allies * 0.10))
        )
        buffed["_ally_buff_count"] = num_allies
        return buffed

    async def on_timeout(self):
        """Se ninguém clicar em 60s, enfrenta sozinho automaticamente"""
        if self.answered:
            return
        self.answered = True
        channel = self._channel
        if not channel:
            return
        try:
            if self._message:
                await self._message.edit(
                    content=f"⏱️ **Tempo esgotado! {self.boss_data['name']} avança sozinho...**\n\n*Enfrentando solo automaticamente!*",
                    embed=None, view=None
                )
        except Exception:
            pass
        await asyncio.sleep(1)
        await fight_boss(channel, self.user_id, is_dungeon=True, dungeon_boss=self.boss_data, allies=None)

    @discord.ui.button(label="Enfrentar Sozinho", style=discord.ButtonStyle.red, emoji="🗡️")
    async def fight_solo(self, interaction: discord.Interaction, button: discord.ui.Button):
        if str(interaction.user.id) != str(self.user_id):
            return await interaction.response.send_message("❌ Essa não é sua dungeon!", ephemeral=True)
        if self.answered:
            return await interaction.response.send_message("❌ Já foi iniciado!", ephemeral=True)
        self.answered = True
        channel = interaction.channel
        self._channel = channel
        await interaction.response.edit_message(
            content=f"🗡️ **Você avança sozinho contra {self.boss_data['name']}!**\n\n*'Nenhum aliado. Apenas você e seu destino.'*",
            embed=None, view=None
        )
        await asyncio.sleep(2)
        await fight_boss(channel, self.user_id, is_dungeon=True, dungeon_boss=self.boss_data, allies=None)

    @discord.ui.button(label="Chamar Aliado", style=discord.ButtonStyle.blurple, emoji="👥")
    async def call_ally(self, interaction: discord.Interaction, button: discord.ui.Button):
        if str(interaction.user.id) != str(self.user_id):
            return await interaction.response.send_message("❌ Essa não é sua dungeon!", ephemeral=True)
        if self.answered:
            return await interaction.response.send_message("❌ Já foi iniciado!", ephemeral=True)
        self.answered = True
        boss_data = self.boss_data
        await interaction.response.edit_message(
            content=(
                f"📣 **{interaction.user.mention} está convocando aliados para a dungeon!**\n\n"
                f"👹 Boss: **{boss_data['name']}** | ❤️ HP: `{boss_data['hp']:,}` | ⚔️ ATK: `{boss_data['atk']}`\n\n"
                f"Use `juntar boss` para participar! O líder usará `iniciar batalha boss` quando pronto."
            ),
            embed=None, view=None
        )
        conn = sqlite3.connect(DB_FILE)
        c = conn.cursor()
        try:
            c.execute("INSERT OR IGNORE INTO boss_battles (boss_name, leader_id, members, world_level) VALUES (?, ?, ?, ?)",
                      (boss_data["name"], str(self.user_id), json.dumps([str(self.user_id)]), 1))
            conn.commit()
        except Exception:
            pass
        finally:
            conn.close()

    @discord.ui.button(label="Chamar Guilda", style=discord.ButtonStyle.green, emoji="🏰")
    async def call_guild(self, interaction: discord.Interaction, button: discord.ui.Button):
        if str(interaction.user.id) != str(self.user_id):
            return await interaction.response.send_message("❌ Essa não é sua dungeon!", ephemeral=True)
        if self.answered:
            return await interaction.response.send_message("❌ Já foi iniciado!", ephemeral=True)
        self.answered = True
        boss_data = self.boss_data
        player = get_player(self.user_id)
        guild_allies = []
        guild_ally_names = []
        if player and player.get("guild_id"):
            try:
                _conn = sqlite3.connect(DB_FILE)
                _c = _conn.cursor()
                _c.execute("SELECT members FROM guilds WHERE id = ?", (player["guild_id"],))
                _row = _c.fetchone()
                _conn.close()
                if _row:
                    _members = json.loads(_row[0])
                    for _mid in _members:
                        if str(_mid) == str(self.user_id):
                            continue
                        _ap = get_player(str(_mid))
                        if _ap and _ap.get("hp", 0) > 0:
                            guild_allies.append(str(_mid))
            except Exception:
                pass
        for _aid in guild_allies:
            try:
                _au = await bot.fetch_user(int(_aid))
                guild_ally_names.append(_au.display_name)
            except:
                guild_ally_names.append(str(_aid))
        _ally_text = f"\n\n🛡️ **Membros convocados:** {', '.join(guild_ally_names[:5])}" if guild_ally_names else "\n\n⚠️ Nenhum membro da guilda online com HP. Lutando sozinho."
        num_allies = len(guild_allies)
        buffed_boss = self.apply_ally_buff(boss_data, num_allies)
        buff_text = ""
        if num_allies > 0:
            buff_text = (
                f"\n\n⚡ **Boss buffado por {num_allies} aliado(s):**"
                f" ❤️ +{num_allies*20}% HP • ⚔️ +{num_allies*10}% ATK"
                f"\n*Mas as recompensas também aumentaram!*"
            )
        channel = interaction.channel
        self._channel = channel
        await interaction.response.edit_message(
            content=f"🏰 **Guilda convocada para enfrentar {buffed_boss['name']}!**{_ally_text}{buff_text}\n\n*A batalha começa...*",
            embed=None, view=None
        )
        await asyncio.sleep(2)
        await fight_boss(channel, self.user_id, is_dungeon=True, dungeon_boss=buffed_boss,
                         allies=guild_allies if guild_allies else None)

    @discord.ui.button(label="Recuar", style=discord.ButtonStyle.gray, emoji="🏃")
    async def flee(self, interaction: discord.Interaction, button: discord.ui.Button):
        if str(interaction.user.id) != str(self.user_id):
            return await interaction.response.send_message("❌ Essa não é sua dungeon!", ephemeral=True)
        if self.answered:
            return await interaction.response.send_message("❌ Já foi iniciado!", ephemeral=True)
        self.answered = True
        await interaction.response.edit_message(
            content="🏃 **Você recua da câmara do boss.**\n\n*'Sábio é quem conhece seus limites.'*",
            embed=None, view=None
        )


class RevengeTrainingView(discord.ui.View):
    """Mostrado ao jogador após derrota em boss de level — opções de Vingança ou Treinamento"""
    def __init__(self, user_id, boss_data, timeout=180):
        super().__init__(timeout=timeout)
        self.user_id = user_id
        self.boss_data = boss_data
        self.answered = False

    @discord.ui.button(label="⚔️ Vingança!", style=discord.ButtonStyle.red, emoji="🔥")
    async def revenge(self, interaction: discord.Interaction, button: discord.ui.Button):
        if str(interaction.user.id) != str(self.user_id):
            return await interaction.response.send_message("❌ Essa escolha não é sua!", ephemeral=True)
        if self.answered:
            return
        self.answered = True
        # Store revenge flag and boss for the next fight
        player = get_player(self.user_id)
        effects = player.get("active_effects", {})
        effects["pending_boss"] = self.boss_data
        effects["used_revenge"] = True
        player["active_effects"] = effects
        save_player_db(self.user_id, player)

        # AUTO-CONVOCAR membros da guilda na revanche
        _r_allies = []
        _r_names = []
        if player.get("guild_id"):
            try:
                _rc = sqlite3.connect(DB_FILE)
                _rcc = _rc.cursor()
                _rcc.execute("SELECT members FROM guilds WHERE id = ?", (player["guild_id"],))
                _rrow = _rcc.fetchone()
                _rc.close()
                if _rrow:
                    for _rm in json.loads(_rrow[0]):
                        if str(_rm) != str(self.user_id):
                            _rap = get_player(str(_rm))
                            if _rap and _rap.get("hp", 0) > 0:
                                _r_allies.append(str(_rm))
                                _r_names.append(_rap.get("name", str(_rm)))
            except Exception:
                pass

        # Buscar nomes reais dos aliados via Discord
        _r_names = []
        for _rid in _r_allies:
            try:
                _rau = await bot.fetch_user(int(_rid))
                _r_names.append(_rau.display_name)
            except:
                _r_names.append(str(_rid))

        _r_ally_text = ""
        if _r_names:
            _r_ally_text = f"\n\n🛡️ **Aliados convocados:** {', '.join(_r_names[:5])}"

        channel = interaction.channel
        await interaction.response.edit_message(
            content=f"🔥 **A raiva te toma! Você avança novamente contra {self.boss_data['name']}!**{_r_ally_text}\n\n*'O ódio pode ser a maior das forças!'*",
            view=None
        )
        await asyncio.sleep(2)
        await fight_boss(channel, self.user_id, allies=_r_allies if _r_allies else None)

