        for i, evo in enumerate(evos):
            stage_num = i + 1
            unlocked = current_stage >= stage_num
            available = player_level >= evo["level"] and current_stage == stage_num - 1
            if unlocked:
                status = "✅ **DESBLOQUEADO**"
