# ================= MODIFICAR EXPLORAR PARA DESCOBRIR LOCAIS =================
@bot.listen("on_message")
async def handle_map_discovery(message):
    """Ao explorar, há chance de descobrir novo local no mapa"""
    if message.author.bot:
        return
    if message.channel.name != CANAL_BETA and message.channel.id not in MUNDO_PROPRIO_CHANNELS.values():
        return
    content = message.content.lower().strip()
    uid = str(message.author.id)

    if content in ["explorar", "explorar região", "explorar regiao"]:
        # Este listener faz a descoberta de locais do reino atual
        await asyncio.sleep(0.5)  # leve delay para não conflitar com o explorar principal
        player = get_player(uid)
        if not player:
            return
        if random.random() < 0.30:  # 30% de chance de descobrir algo
            # ✅ CORREÇÃO: usa current_world (reino viajado) e não max(worlds)
            cw = player.get("current_world")
            if cw is not None:
                world_key = int(cw)
            else:
                world_key = max(int(w) for w in player.get("worlds", [1]))
            # Garante que o world_key existe no MAP_LOCATIONS
            if world_key not in MAP_LOCATIONS:
                world_key = max((k for k in MAP_LOCATIONS.keys() if k <= world_key), default=1)

            world_locs = MAP_LOCATIONS.get(world_key, {}).get("locations", [])
            disc = player.get("discovered_map", {})
            key = str(world_key)
            known = disc.get(key, [])
            unknown = [l for l in world_locs if not l["discovered"] and l["id"] not in known]
            if unknown:
                new_loc = random.choice(unknown)
                discover_location(uid, world_key, new_loc["id"])
                type_icons = {
                    "cidade": "🏙️", "recurso": "⛏️", "dungeon": "🕳️", "dungeon_secreta": "🔮",
                    "boss_local": "💀", "lore": "📜", "loja": "🏪", "crafting": "⚒️",
                    "portal": "🌀", "evento_especial": "⭐", "npc_especial": "🧙"
                }
                icon = type_icons.get(new_loc["type"], "📍")
                world_name = MAP_LOCATIONS.get(world_key, {}).get("world_name", "")
                await message.channel.send(
                    embed=discord.Embed(
                        title=f"🗺️ Novo Local Descoberto!",
                        description=(
                            f"{icon} **{new_loc['name']}** foi adicionado ao seu mapa!\n"
                            f"📍 Reino: **{world_name}**\n"
                            f"Use `abrir mapa` para ver."
                        ),
                        color=discord.Color.teal()
                    )
                )

