            title=f"📋 RELATÓRIO DE EQUIPAMENTOS — {target.display_name}",
            description=f"**Nível:** {player.get('level', 1)} | **Classe:** {player.get('class', 'Nenhuma')} | **Raça:** {player.get('race', 'Nenhuma')}",
