        if now - last_heal < 600:
            rest = int(600 - (now - last_heal))
            await message.channel.send(f"💚 Suas mãos ainda brilham da última cura. Próxima em **{rest//60}m {rest%60}s**.")
            return
        target = message.mentions[0]
